template <typename T, int SIZE_X, int SIZE_Y, int BOUNDARY_X>
class TransformBuffer {
public:
    enum {
        VERTICAL_STRIDE = BOUNDARY_X + (SIZE_X / 2)
    };

private:
    enum {
        SHM_BANKS = 16,
        BUFFER_SIZE = VERTICAL_STRIDE * SIZE_Y,
        PADDING = SHM_BANKS - ((BUFFER_SIZE + SHM_BANKS / 2) % SHM_BANKS),
        ODD_OFFSET = BUFFER_SIZE + PADDING,
    };

    T data[2 * BUFFER_SIZE + PADDING];

    template <typename FUNC>
    void horizontalStep(const int count, const int prevOffset, const int midOffset, const int nextOffset, const FUNC & function, int threadIdx_x) {
        const int STEPS = count / SIZE_X;
        const int finalCount = count % SIZE_X;
        const int finalOffset = count - finalCount;

        for(int i = 0; i < STEPS; i++) {
            const T previous = data[prevOffset + i * SIZE_X + threadIdx_x];
            const T next = data[nextOffset + i * SIZE_X + threadIdx_x];
            T & center = data[midOffset + i * SIZE_X + threadIdx_x];
            function(previous, center, next);
        }

        if(threadIdx_x < finalCount) {
            const T previous = data[prevOffset + finalOffset + threadIdx_x];
            const T next = data[nextOffset + finalOffset + threadIdx_x];
            T & center = data[midOffset + finalOffset + threadIdx_x];
            function(previous, center, next);
        }
    }

public:
    int getColumnOffset(int columnIndex) {
        columnIndex += BOUNDARY_X;
        return columnIndex / 2 + (columnIndex & 1) * ODD_OFFSET;
    }

    T & operator[] (const int index) {
        return data[index];
    }

    template <typename FUNC>
    void forEachHorizontalEven(const int firstLine, const int numLines, const FUNC & func, int threadIdx_x) {
        const int count = numLines * VERTICAL_STRIDE - 1;
        const int centerOffset = firstLine * VERTICAL_STRIDE + 1;
        const int prevOffset = firstLine * VERTICAL_STRIDE + ODD_OFFSET;
        const int nextOffset = prevOffset + 1;
        horizontalStep(count, prevOffset, centerOffset, nextOffset, func, threadIdx_x);
    }

    template <typename FUNC>
    void forEachHorizontalOdd(const int firstLine, const int numLines, const FUNC & func, int threadIdx_x) {
        const int count = numLines * VERTICAL_STRIDE - 1;
        const int prevOffset = firstLine * VERTICAL_STRIDE;
        const int centerOffset = prevOffset + ODD_OFFSET;
        const int nextOffset = prevOffset + 1;
        horizontalStep(count, prevOffset, centerOffset, nextOffset, func, threadIdx_x);
    }

    template <typename F>
    void forEachVerticalEven(const int columnOffset, const F & f, int threadIdx_x) {
        if(SIZE_Y > 3) {
            const int steps = SIZE_Y / 2 - 1;
            for(int i = 0; i < steps; i++) {
                const int row = 2 + i * 2;
                const T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
                const T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
                f(prev, data[columnOffset + row * VERTICAL_STRIDE], next);
            }
        }
    }

    template <typename F>
    void forEachVerticalOdd(const int columnOffset, const F & f, int threadIdx_x) {
        const int steps = (SIZE_Y - 1) / 2;
        for(int i = 0; i < steps; i++) {
            const int row = i * 2 + 1;
            const T prev = data[columnOffset + (row - 1) * VERTICAL_STRIDE];
            const T next = data[columnOffset + (row + 1) * VERTICAL_STRIDE];
            f(prev, data[columnOffset + row * VERTICAL_STRIDE], next);
        }
    }

    void scaleHorizontal(const T evenScale, const T oddScale, const int firstLine, const int numLines, int threadIdx_x) {
        const int offset = firstLine * VERTICAL_STRIDE;
        const int count = numLines * VERTICAL_STRIDE;
        const int steps = count / SIZE_X;
        const int finalCount = count % SIZE_X;
        const int finalOffset = count - finalCount;

        for(int i = 0; i < steps; i++) {
            data[threadIdx_x + i * SIZE_X + offset] *= evenScale;
            data[threadIdx_x + i * SIZE_X + offset + ODD_OFFSET] *= oddScale;
        }

        if(threadIdx_x < finalCount) {
            data[threadIdx_x + finalOffset + offset] *= evenScale;
            data[threadIdx_x + finalOffset + offset + ODD_OFFSET] *= oddScale;
        }
    }

    void scaleVertical(const T evenScale, const T oddScale, const int columnOffset, const int numLines, const int firstLine) {
        for(int i = firstLine; i < (numLines + firstLine); i++) {
            if(i & 1) {
                data[columnOffset + i * VERTICAL_STRIDE] *= oddScale;
            } else {
                data[columnOffset + i * VERTICAL_STRIDE] *= evenScale;
            }
        }
    }
};

